mapper.select:
SELECT m.* FROM sys_flow_model m

    m.del_flag = '0'

        AND m.model_name LIKE CONCAT('%', #{modelName}, '%')


        AND m.category IN (
            SELECT c.id FROM sys_flow_category c
            WHERE c.id = #{category}
               OR c.ancestors LIKE CONCAT('%', #{category}, '/%')
        )


        AND m.status = #{status}


ORDER BY m.create_time DESC
